sql:
SELECT cities.name AS city_name, demographics.black AS black_population
FROM cities
JOIN demographics ON cities.city_id = demographics.city_id;

SELECT 
    (SELECT AVG(population) FROM cities) AS avg_population_all_cities,
    (SELECT AVG(population) FROM cities WHERE urban > 0.5) AS avg_population_urban_cities;

external_knowledge:
- Low community tensions refer to a low violent crime rate (less than 0.0015);
- High academic achievement is indicated by test scores (greater than 75);
- A significant black population means a racial segregation index of 90 or more;
- A comfortable living standard implies a median household income greater than $50,000.

sql:
SELECT DISTINCT cities.name
FROM cities
INNER JOIN demographics ON cities.city_id = demographics.city_id;

external_knowledge:
- 'sizable cities' refers to cities with a population over 500,000;
- 'low racial and income disparities' mean racial and income segregation indices below 0.07;
- 'high median incomes' imply median household income greater than $75,000.

sql:
SELECT city_id, violent_crime
FROM crime
ORDER BY violent_crime DESC;

SELECT AVG(income) AS average_income
FROM economy
WHERE unemployment_rate < (SELECT AVG(unemployment_rate) FROM economy);

SELECT city_id, income AS max_avg_income
FROM economy
WHERE income = (
    SELECT MAX(income)
    FROM economy
);

SELECT name, population, urban, mobility, latitude, longitude
FROM cities
ORDER BY population DESC;

SELECT T1.name, T1.urban, T1.population, T2.income, T2.unemployment_rate
FROM cities AS T1
INNER JOIN economy AS T2 ON T1.city_id = T2.city_id;
